import { describe, expect, it } from 'vitest';
import type { TopologyAlphaStyleBackend } from '../src/style-transfer-topology-glue';
import { styleTransferAnyImage } from '../src/style-transfer-any-image';

function makePlane(w: number, h: number, seed: number): Float32Array {
  const out = new Float32Array(w * h * 3);
  let s = seed >>> 0;
  const rand = () => {
    s = (s * 1664525 + 1013904223) >>> 0;
    return s / 0xffffffff;
  };
  for (let i = 0; i < out.length; i++) out[i] = rand();
  return out;
}

describe('styleTransferAnyImage', () => {
  it('returns image-sized stylized output with bounded values', async () => {
    const width = 32;
    const height = 32;
    const content = makePlane(width, height, 1);
    const style = makePlane(width, height, 2);

    const result = await styleTransferAnyImage(
      { data: content, width, height, channels: 3 },
      { data: style, width, height, channels: 3 },
      { method: 'classical', strength: 0.75, structurePreservation: 0.6 },
    );

    expect(result.width).toBe(width);
    expect(result.height).toBe(height);
    expect(result.channels).toBe(3);
    expect(result.stylized.length).toBe(width * height * 3);
    expect(result.methodUsed).toBe('classical');
    expect(result.styleDistance).toBeGreaterThanOrEqual(0);
    expect(result.alphaWaveUsed.enabled).toBe(true);
    expect(result.alphaWaveUsed.meanAlpha).toBeGreaterThan(0);
    expect(result.alphaWaveUsed.meanAlpha).toBeLessThanOrEqual(1);
    for (let i = 0; i < result.stylized.length; i++) {
      expect(result.stylized[i]).toBeGreaterThanOrEqual(0);
      expect(result.stylized[i]).toBeLessThanOrEqual(1);
    }
  });

  it('supports disabling alpha wave', async () => {
    const width = 16;
    const height = 16;
    const content = makePlane(width, height, 11);
    const style = makePlane(width, height, 12);
    const result = await styleTransferAnyImage(
      { data: content, width, height, channels: 3 },
      { data: style, width, height, channels: 3 },
      { method: 'classical', alphaWave: false },
    );
    expect(result.alphaWaveUsed.enabled).toBe(false);
    expect(result.alphaWaveUsed.meanAlpha).toBe(1);
  });

  it('alpha-wave settings change transposition field', async () => {
    const width = 16;
    const height = 16;
    const content = makePlane(width, height, 31);
    const style = makePlane(width, height, 32);
    const a = await styleTransferAnyImage(
      { data: content, width, height, channels: 3 },
      { data: style, width, height, channels: 3 },
      { method: 'classical', alphaWave: { frequency: 1.2, phase: 0 } },
    );
    const b = await styleTransferAnyImage(
      { data: content, width, height, channels: 3 },
      { data: style, width, height, channels: 3 },
      { method: 'classical', alphaWave: { frequency: 3.8, phase: 1.1 } },
    );
    expect(Math.abs(a.alphaWaveUsed.meanAlpha - b.alphaWaveUsed.meanAlpha)).toBeGreaterThan(1e-4);
  });

  it('rejects mismatched geometry', async () => {
    await expect(
      styleTransferAnyImage(
        { data: makePlane(16, 16, 3), width: 16, height: 16, channels: 3 },
        { data: makePlane(32, 32, 4), width: 32, height: 32, channels: 3 },
      ),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('meshGate enabled attaches meshProvenance and optional depth', async () => {
    const width = 16;
    const height = 16;
    const n = width * height;
    const content = makePlane(width, height, 41);
    const style = makePlane(width, height, 42);
    const depthConfidence = new Float32Array(n);
    depthConfidence.fill(0.75);
    const backend: TopologyAlphaStyleBackend = {
      async buildTopologyAlphaForStyle(req) {
        const a = new Float32Array(req.width * req.height);
        a.fill(0.6);
        return { alpha: a, provenanceFragment: { test: 'wasm-mock' } };
      },
    };
    const result = await styleTransferAnyImage(
      { data: content, width, height, channels: 3 },
      { data: style, width, height, channels: 3 },
      {
        method: 'classical',
        meshGate: { enabled: true, depthConfidence },
      },
      undefined,
      backend,
    );
    expect(result.meshProvenance?.schema_version).toBe(1);
    expect(result.meshProvenance?.topology_source).toBe('wasm');
    expect(result.meshProvenance?.optional_depth_used).toBe(true);
    expect(result.meshProvenance?.channels.length).toBe(6);
    expect(result.meshFoldMetrics?.mean_depth_confidence).toBeCloseTo(0.75, 5);
  });
});
